INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('optician-moex-00519', 'optician', 'optician-moex-112-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '隱形眼鏡護理液的基本成分為緩衝液，其pH值需保持在多少才能維持隱形眼鏡配戴所需之酸鹼值？', '["2～5", "4～6", "6～8", "8～10"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "5763fac48738", "answer_pdf_sha1": "feb21889645c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00520', 'optician', 'optician-moex-112-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關雙氧保養液（hydrogenperoxide），下列何者正確？', '["雙氧保養液主要包含5%的雙氧水以及中和錠（neutralizingtablet）", "中和錠需至少作用12小時後才能配戴隱形眼鏡", "使用雙氧保養液（hydrogenperoxide）的隱形眼鏡保存盒應該每6個月更換一次", "雙氧保養液（hydrogenperoxide）通常是無防腐劑的"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "5763fac48738", "answer_pdf_sha1": "feb21889645c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00521', 'optician', 'optician-moex-112-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關軟式隱形眼鏡之敘述，下列何者錯誤？', '["將軟式隱形眼鏡從室溫的保存盒取出戴至眼睛表面時，離子型（ionic）的軟式隱形眼鏡較非離子型（non- ionic）的會更縮小", "一般來說，為了方便配戴，高含水（60%以上）的軟式隱形眼鏡（hydrogel）的鏡片中央厚度（centrethickness） 會做得比中含水（50-59%）的軟式隱形眼鏡來的厚", "軟式隱形眼鏡的邊緣較厚（thickeredge）的，通常戴起來會較鬆（looserfit）", "軟式隱形眼鏡的邊緣形狀為較薄的刀型和鑿型設計通常提供較好的舒適度"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "5763fac48738", "answer_pdf_sha1": "feb21889645c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00522', 'optician', 'optician-moex-112-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '隱形眼鏡片的適配性，可以藉由以下幾個特徵來評估，有關配戴相對較鬆的鏡片的表現何者錯誤？', '["相較於偏緊的鏡片，較鬆的鏡片異物感較輕微", "當下眼瞼縮回時，鏡片會快速落下", "邊緣可能發生翹起，尤其是在顳部下緣", "有時會在眨眼時，出現偏心和過度運動（≥ 0.5 mm）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "5763fac48738", "answer_pdf_sha1": "feb21889645c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00523', 'optician', 'optician-moex-112-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '為眼睛具高散光（大於2.50D）的病患驗配隱形眼鏡必須做許多方面的考量，下列敘述何者錯誤？', '["在高角膜散光病患即使使用球面硬式隱形眼鏡（sphericalgas-permeablelenses），也是可以成功", "若眼睛散光最主要由水晶體造成，角膜是沒散光的，那麼球面硬式隱形眼鏡較不適合使用", "在散光來源為角膜的病患，後表面曲面鏡片設計（backsurfacetoriclensdesign）與雙曲面鏡片設計（bitoric lensdesign）具有使後鏡片表面與角膜更好地貼合的優點，也因此，鏡片在角膜上比較不易偏移，也不易 產生一些不良視覺現象", "目前，質量控制的改進、視力質量的提高和氧氣透過率的提高使得軟式散光隱形眼鏡成為一種選擇。因 此角膜的高度不規則散光，目前也傾向使用軟式隱形鏡片矯正"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "5763fac48738", "answer_pdf_sha1": "feb21889645c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00524', 'optician', 'optician-moex-112-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列那項不是配適良好的軟式鏡片？', '["良好地居中在角膜中央，並表現出大約 0.50mm的移動", "與其他視線相比，在向上視線中，通常鏡片移動得較多", "當向上看時，鏡片向下落，且沒有覆蓋上角膜", "正的鏡片向上推測試（positivepush-uptest）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "5763fac48738", "answer_pdf_sha1": "feb21889645c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00525', 'optician', 'optician-moex-112-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '鏡架度數為OD-4.75D/OS-4.50D，當兩眼戴上隱形眼鏡鏡片度數-4.00D後，且插片驗光為OD-0.50DVA', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "5763fac48738", "answer_pdf_sha1": "feb21889645c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 20, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00526', 'optician', 'optician-moex-112-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '0/OS-0.25DVA1.0，兩眼應訂多少隱形眼鏡度數，以達到每眼視力1.0？', '["OD-4.75D/OS-4.50D", "OD-4.75D/OS-4.25D", "OD-5.00D/OS-4.50D", "OD-4.50D/OS-4.25D"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "5763fac48738", "answer_pdf_sha1": "feb21889645c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00527', 'optician', 'optician-moex-112-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '軟式隱形眼鏡裝配太鬆時，可以見到眨眼時鏡片移動超過多少範圍？', '["0.10mm", "0.20mm", "0.50mm", "1.0mm"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "5763fac48738", "answer_pdf_sha1": "feb21889645c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00528', 'optician', 'optician-moex-112-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '在軟式鏡片上施加的作用力，下列敘述何者錯誤？', '["擠壓與鏡片在眼睛上移動所需之力的大小，與鏡片的合適程度有關", "因淚液具黏性，鏡片為與眼睛形狀相貼合而產生的形變，造成後淚膜的壓力", "移動鏡片所需的力，也與鏡片前淚膜的黏度有關", "與硬式鏡片相比，軟式鏡片的滯留力相對較大，因此重力的影響較小"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:28+00:00", "source_pdf_sha1": "5763fac48738", "answer_pdf_sha1": "feb21889645c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
